+		return
+	}
+
+	// Report findings
+	now := time.Now().Format("15:04:05")
+	totalTargets := len(plan.LimitedSessions) + len(plan.NearLimitSessions)
+	if totalTargets == 0 {
+		fmt.Printf(" [%s] %s\n", style.Dim.Render(now), style.Dim.Render("all clear"))
+		return
